mapper.select:
SELECT v.VISITOR_ID, vp.NICKNAME AS visitorNickname, vp.AVATAR AS visitorAvatar, v.USER_ID, u.USERNAME, v.IP, CONCAT(v.COUNTRY, v.PROVINCE, v.CITY, v.DISTRICT) AS ipRegion, v.ISP, CONCAT(v.BROWSER, v.BROWSER_VERSION) AS BROWSER, v.DEVICE_TYPE, v.FIRST_VISIT_TIME, v.LAST_VISIT_DATE FROM visitor v LEFT JOIN visitor_profile vp ON vp.VISITOR_ID = v.VISITOR_ID LEFT JOIN user u ON u.ID = v.USER_ID
AND u.USERNAME = #{query.username}
AND v.IP = #{query.ip}
ORDER BY v.LAST_VISIT_DATE DESC
